from flask import Flask, session, request, jsonify
from redis import Redis
from functools import wraps
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'
redis_client = Redis(host='localhost', port=6379, db=0)

def cache(expiration=60):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"cache:{request.path}"
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify(eval(cached_result))
            result = f(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            return jsonify(result)
        return decorated_function
    return decorator

@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(f"session:{session_id}")
        if session_data:
            session.update(eval(session_data))

@app.after_request
def save_session(response):
    session_id = request.cookies.get('session_id')
    if not session_id:
        session_id = str(time.time())
        response.set_cookie('session_id', session_id)
    redis_client.setex(f"session:{session_id}", 3600, str(dict(session)))
    return response

@app.route('/expensive_query')
@cache(expiration=120)
def expensive_query():
    # Simulate an expensive database query
    time.sleep(5)
    return {'data': 'Expensive query result'}

@app.route('/set_session/<key>/<value>')
def set_session(key, value):
    session[key] = value
    return f"Session data set: {key} = {value}"

@app.route('/get_session/<key>')
def get_session(key):
    return session.get(key, 'Key not found')

